87	/// `Home::WorkspaceCode` or `Home::WorkspaceBot`.
88	fn in_workspace_group(key: &ConfigKey) -> bool {
89	    key.homes.contains(&Home::WorkspaceCode) || key.homes.contains(&Home::WorkspaceBot)
90	}
91	
92	/// Split a dotted key path on its last `.` into `(section, leaf)`.
93	///
94	/// A path with no `.` (none exist in the current schema) falls
95	/// back to an empty section so the key still renders under a
96	/// blank `[]` header rather than panicking.
97	fn section_and_leaf(path: &str) -> (&str, &str) {
98	    match path.rfind('.') {
99	        Some(idx) => (&path[..idx], &path[idx + 1..]),
100	        None => ("", path),
101	    }
102	}
103	
104	/// Render a key's value cell: the quoted/bare default, or an
105	/// angle-bracket placeholder by kind when there is no default —
106	/// except a required key with no default, which renders
107	/// `<required>` so it stands out.
108	fn render_value(key: &ConfigKey) -> String {
109	    match key.default {
110	        Some(d) => match key.kind {
111	            ValueKind::Usize => d.to_string(),
112	            ValueKind::Str | ValueKind::ItemList => format!("{d:?}"),
113	        },
114	        None => {
115	            if key.required {
116	                "<required>".to_string()
117	            } else {
118	                match key.kind {
119	                    ValueKind::Str => "<str>".to_string(),
120	                    ValueKind::Usize => "<usize>".to_string(),
121	                    ValueKind::ItemList => "<items>".to_string(),
122	                }
123	            }
124	        }
125	    }
126	}
