128	/// Print one home group: a divider, then each key grouped by
129	/// section (schema order, first-seen section order), one
130	/// `[section]` header per section.
131	fn print_group(title: &str, path_hint: &str, keys: &[&ConfigKey]) {
132	    info!("# ── {title} config: {path_hint} ──");
133	    let mut sections: Vec<&str> = Vec::new();
134	    for key in keys {
135	        let (section, _leaf) = section_and_leaf(key.path);
136	        if !sections.contains(&section) {
137	            sections.push(section);
138	        }
139	    }
140	    for section in sections {
141	        info!("[{section}]");
142	        for key in keys {
143	            let (key_section, leaf) = section_and_leaf(key.path);
144	            if key_section != section {
145	                continue;
146	            }
147	            let prefix = if key.required { "" } else { "# " };
148	            let value = render_value(key);
149	            info!("{prefix}{leaf} = {value}   # {}", key.doc);
150	        }
151	    }
152	    info!("");
153	}
154	
155	/// True if `actual` (a dotted key from a loaded config file) is
156	/// recognized by some `schema()` entry whose homes satisfy
157	/// `home_pred`.
158	///
159	/// - Non-dynamic entries match by exact path equality.
160	/// - Dynamic entries (`key.dynamic`) match segment-wise: equal
161	///   segment counts, each entry segment either equal to the actual
162	///   segment or a `<placeholder>` matching any single segment.
163	fn key_known(actual: &str, home_pred: impl Fn(&[Home]) -> bool) -> bool {
164	    schema().iter().any(|key| {
165	        if !home_pred(key.homes) {
166	            return false;
167	        }
168	        if !key.dynamic {
169	            return key.path == actual;
170	        }
171	        let entry_segs: Vec<&str> = key.path.split('.').collect();
172	        let actual_segs: Vec<&str> = actual.split('.').collect();
173	        entry_segs.len() == actual_segs.len()
174	            && entry_segs
175	                .iter()
176	                .zip(actual_segs.iter())
177	                .all(|(e, a)| e == a || (e.starts_with('<') && e.ends_with('>')))
178	    })
179	}
180	
181	/// Validate one config file against the schema, filtered to the
182	/// homes accepted at that file by `home_pred`.
183	///
184	/// - A missing file is not an error — `info!`s that it's absent
185	///   and returns `Ok(0)`.
186	/// - Each key not recognized by `key_known` is reported with
187	///   `warn!`, naming `label` and the key; keys are checked in
188	///   sorted order for stable output.
189	/// - Returns the count of unknown keys found. A load error
190	///   (malformed TOML) propagates as `Err`.
191	fn validate_file(
192	    path: &std::path::Path,
193	    label: &str,
194	    home_pred: impl Fn(&[Home]) -> bool,
195	) -> Result<usize, Box<dyn Error>> {
196	    if !path.exists() {
197	        info!("{label}: {} not found — skipping", path.display());
198	        return Ok(0);
199	    }
200	    let map = toml_load(path)?;
201	    let mut keys: Vec<&String> = map.keys().collect();
202	    keys.sort();
203	
204	    let mut unknown = 0;
205	    for key in keys {
206	        if !key_known(key, &home_pred) {
207	            warn!("{label} ({}): unknown key {key:?}", path.display());
208	            unknown += 1;
209	        }
210	    }
211	    Ok(unknown)
212	}
213	
214	/// Validate the selected home(s)' config file(s) against the
215	/// schema, returning the total count of unknown keys.
216	fn validate(params: &ConfigParams) -> Result<usize, Box<dyn Error>> {
217	    let mut unknown = 0;
218	
219	    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
220	        unknown += validate_file(&config_path()?, "user config", |homes| {
221	            homes.contains(&Home::User)
222	        })?;
223	    }
224	
225	    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
226	        match find_workspace_root() {
227	            Some(root) => {
228	                unknown +=
229	                    validate_file(&root.join(VC_CONFIG_FILE), "workspace config", |homes| {
230	                        homes.contains(&Home::WorkspaceCode) || homes.contains(&Home::WorkspaceBot)
231	                    })?;
232	            }
233	            None => info!("workspace config: not inside a workspace — skipping"),
234	        }
235	    }
236	
237	    Ok(unknown)
238	}
239	
240	/// Print the settable config schema, grouped by config home then
241	/// TOML section (`--home` selects which home group(s) to print),
242	/// or — with `--validate` — check the config file(s) for unknown
243	/// keys and exit non-zero if any are found.
244	pub fn config(_ctx: &Context, params: &ConfigParams) -> Result<(), Box<dyn std::error::Error>> {
245	    if params.validate {
246	        let total = validate(params)?;
247	        return if total > 0 {
248	            Err(format!("config: {total} unknown key(s) found").into())
249	        } else {
250	            info!("config: all keys recognized");
251	            Ok(())
252	        };
253	    }
254	
255	    info!(
256	        "# vc-x1 settable config keys (from vc-x1 {})",
257	        env!("CARGO_PKG_VERSION")
258	    );
259	    info!("");
260	
261	    let all_keys = schema();
262	
263	    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
264	        let user_keys: Vec<&ConfigKey> = all_keys.iter().filter(|k| in_user_group(k)).collect();
265	        print_group("User", "~/.config/vc-x1/config.toml", &user_keys);
266	    }
267	
268	    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
269	        let workspace_keys: Vec<&ConfigKey> =
270	            all_keys.iter().filter(|k| in_workspace_group(k)).collect();
271	        print_group("Workspace", "<root>/.vc-config.toml", &workspace_keys);
272	    }
273	
274	    Ok(())
275	}
