246	/// Replace the first line of `<dir>/README.md` with `# <name>`. If
247	/// `README.md` is absent, this is a no-op. Trailing content after the
248	/// first newline is preserved verbatim; a file with no newline becomes
249	/// just `# <name>`.
250	pub(crate) fn rewrite_readme_first_line(
251	    dir: &Path,
252	    name: &str,
253	) -> Result<(), Box<dyn std::error::Error>> {
254	    let readme = dir.join("README.md");
255	    if !readme.exists() {
256	        return Ok(());
257	    }
258	    let content = std::fs::read_to_string(&readme)?;
259	    let rest = match content.find('\n') {
260	        Some(pos) => &content[pos..],
261	        None => "",
262	    };
263	    let new_content = format!("# {name}{rest}");
264	    std::fs::write(&readme, new_content)?;
265	    debug!("rewrote first line of {}", readme.display());
266	    Ok(())
267	}
