343	/// Renders a commented block documenting every settable workspace
344	/// config key not already covered by the active `[workspace]`
345	/// block above — currently the `push.*` and `bot-session.*`
346	/// families, sourced from `config_schema::schema()` so this list
347	/// cannot drift from the schema.
348	///
349	/// Grouped by TOML section (schema/first-seen order); each key is
350	/// emitted as `# <leaf> = <value>   # <doc>` so the whole block
351	/// parses as comments only.
352	fn render_optional_keys_block() -> String {
353	    use crate::config_schema::{Home, ValueKind, schema};
354	
355	    let mut out = String::new();
356	    out.push_str(
357	        "\n# Optional keys — uncomment and edit to override the built-in\n\
358	         # default. `vc-x1 config` prints this list from the binary.\n",
359	    );
360	
361	    let mut current_section: Option<String> = None;
362	    for key in schema() {
363	        if key.path.starts_with("workspace.") {
364	            continue;
365	        }
366	        if !key
367	            .homes
368	            .iter()
369	            .any(|h| matches!(h, Home::WorkspaceCode | Home::WorkspaceBot))
370	        {
371	            continue;
372	        }
373	        let (section, leaf) = match key.path.rsplit_once('.') {
374	            Some((s, l)) => (s, l),
375	            None => ("", key.path),
376	        };
377	        if current_section.as_deref() != Some(section) {
378	            out.push_str(&format!("\n[{section}]\n"));
379	            current_section = Some(section.to_string());
380	        }
381	        let Some(default) = key.default else {
382	            continue;
383	        };
384	        let value = match key.kind {
385	            ValueKind::Usize => default.to_string(),
386	            ValueKind::Str | ValueKind::ItemList => format!("\"{default}\""),
387	        };
388	        out.push_str(&format!("# {leaf} = {value}   # {}\n", key.doc));
389	    }
390	
391	    out
392	}
