477	/// Expand `~` and `$VAR` / `${VAR}` substitutions in a user string.
478	///
479	/// - `~` and `~/…` resolve via `HOME`.
480	/// - Unset env vars are a fatal error (silent empty substitution
481	///   would mask typos).
482	/// - Bare `$` with no identifier after stays literal.
483	pub(crate) fn expand_vars(s: &str) -> Result<String, Box<dyn std::error::Error>> {
484	    let home_expanded = if s == "~" {
485	        std::env::var("HOME").map_err(|_| "HOME is not set; cannot expand '~'")?
486	    } else if let Some(rest) = s.strip_prefix("~/") {
487	        let home = std::env::var("HOME").map_err(|_| "HOME is not set; cannot expand '~/'")?;
488	        format!("{home}/{rest}")
489	    } else {
490	        s.to_string()
491	    };
492	
493	    let mut out = String::with_capacity(home_expanded.len());
494	    let mut chars = home_expanded.chars().peekable();
495	    while let Some(c) = chars.next() {
496	        if c != '$' {
497	            out.push(c);
498	            continue;
499	        }
500	        let (name, braced) = if chars.peek() == Some(&'{') {
501	            chars.next(); // OK: peeked '{' above, next() must yield it
502	            let mut name = String::new();
503	            let mut closed = false;
504	            for c2 in chars.by_ref() {
505	                if c2 == '}' {
506	                    closed = true;
507	                    break;
508	                }
509	                name.push(c2);
510	            }
511	            if !closed {
512	                return Err(format!("unterminated '${{…}}' in '{s}'").into());
513	            }
514	            (name, true)
515	        } else {
516	            let mut name = String::new();
517	            while let Some(&c2) = chars.peek() {
518	                if c2.is_ascii_alphanumeric() || c2 == '_' {
519	                    name.push(c2);
520	                    chars.next();
521	                } else {
522	                    break;
523	                }
524	            }
525	            (name, false)
526	        };
527	        if name.is_empty() {
528	            out.push('$');
529	            if braced {
530	                out.push_str("{}");
531	            }
532	            continue;
533	        }
534	        let val =
535	            std::env::var(&name).map_err(|_| format!("env var '${name}' is not set (in '{s}')"))?;
536	        out.push_str(&val);
537	    }
538	    Ok(out)
539	}
