541	/// True when `s` looks like a git remote URL rather than a path.
542	///
543	/// - Scheme-qualified (`scheme://…`).
544	/// - scp-like SSH form (`user@host:path`).
545	/// - Everything else is treated as a path.
546	pub(crate) fn is_remote_url(s: &str) -> bool {
547	    if s.contains("://") {
548	        return true;
549	    }
550	    if let Some(at) = s.find('@')
551	        && let Some(colon) = s.find(':')
552	        && at < colon
553	        && !s[..at].contains('/')
554	    {
555	        return true;
556	    }
557	    false
558	}
