560	/// True when `s` is a GitHub URL (host-based detection).
561	///
562	/// - SSH scp-like (`git@github.com:…`).
563	/// - `ssh://git@github.com/…`.
564	/// - `https://github.com/…` and `http://github.com/…`.
565	/// - GitHub URLs route to the `gh repo create` provisioner.
566	pub(crate) fn is_github_url(s: &str) -> bool {
567	    s.starts_with("git@github.com:")
568	        || s.starts_with("ssh://git@github.com/")
569	        || s.starts_with("https://github.com/")
570	        || s.starts_with("http://github.com/")
571	}
