573	/// Normalize a `--repo local=<parent>` value: expand variables,
574	/// make absolute. Parent doesn't need to exist yet — init creates
575	/// it.
576	pub(crate) fn normalize_local_parent(s: &str) -> Result<PathBuf, Box<dyn std::error::Error>> {
577	    let s = s.trim();
