652	/// Build an `InitPlan` from CLI args + user config.
653	///
654	/// Dispatches on the parsed `<TARGET>` form:
655	///
656	/// - `Url(u)` / `OwnerName(o, n)` → URL is explicit; config not
657	///   consulted; `--account` and `--repo` are rejected as
658	///   meaningless.
659	/// - `Path(p)` → `p` is the destination; basename names the repo;
660	///   remote URL resolved from config via the `--repo` chain.
661	/// - `BareName(n)` → destination at `cwd/<n>`; remote resolved
662	///   from config.
663	///
664	/// The `cfg` parameter is the loaded user config; `init` loads it
665	/// once at entry and passes it through so tests can supply a
666	/// synthetic config without touching disk.
667	pub(crate) fn plan_init(
668	    params: &InitParams,
669	    cfg: &UserConfig,
670	) -> Result<InitPlan, Box<dyn std::error::Error>> {
671	    debug!(
672	        "init args: target={:?}, name={:?}, account={:?}, repo={:?}, por={}, private={}",
673	        params.target, params.name, params.account, params.repo, params.por, params.private
674	    );
675	
676	    let scope = if params.por {
677	        Scope(vec![Side::Code])
678	    } else {
679	        Scope(vec![Side::Code, Side::Bot])
680	    };
681	
682	    if scope.is_code_only()
683	        && let Some(t) = &params.use_template
684	        && t.contains(',')
685	    {
686	        return Err(format!(
687	            "--por takes a single template path; got '{t}' (drop the `,BOT` half)"
688	        )
689	        .into());
690	    }
691	
692	    if params.config.is_some() && !params.por {
693	        return Err(
694	            "--config is only valid with --por (dual configs are per-side and unconditional)"
695	                .into(),
696	        );
697	    }
698	    if let Some(ConfigKind::Path(p)) = &params.config
699	        && !p.exists()
700	    {
701	        return Err(format!("--config: path does not exist: {}", p.display()).into());
702	    }
703	
704	    let parsed = parse_target(&params.target)?;
705	    debug!("parse_target: {:?} → {:?}", params.target, parsed);
706	    let plan = match parsed {
707	        Target::Url(url) => plan_from_url(params, scope, url),
708	        Target::OwnerName(o, n) => {
709	            plan_from_url(params, scope, format!("git@github.com:{o}/{n}.git"))
710	        }
711	        Target::Path(p) => plan_from_path(params, scope, p, cfg),
712	        Target::BareName(n) => plan_from_bare_name(params, scope, n, cfg),
713	    }?;
714	    debug!(
715	        "plan_init: project_dir={}, name={}, code_url={}, provisioner={:?}, gh_code_slug={:?}, code_bare_path={:?}, session_url={:?}",
716	        plan.project_dir.display(),
717	        plan.name,
718	        plan.code_url,
719	        plan.provisioner,
720	        plan.gh_code_slug,
721	        plan.code_bare_path,
722	        plan.session_url,
723	    );
724	    Ok(plan)
725	}
