727	/// Plan when TARGET is a URL or `owner/name` shorthand.
728	///
729	/// - URL is explicit; config not consulted.
730	/// - `--account` / `--repo` are rejected (would have no effect).
731	/// - `[NAME]` overrides the URL-derived directory name.
732	fn plan_from_url(
733	    params: &InitParams,
734	    scope: Scope,
735	    url: String,
736	) -> Result<InitPlan, Box<dyn std::error::Error>> {
737	    if params.account.is_some() {
738	        return Err(
739	            "--account is meaningless with a URL or owner/name TARGET (config not consulted)"
740	                .into(),
741	        );
742	    }
743	    if params.repo.is_some() {
744	        return Err(
745	            "--repo is meaningless with a URL or owner/name TARGET (config not consulted)".into(),
746	        );
747	    }
748	    let code_url = ensure_git_suffix(&url);
749	    let derived_name = derive_name(&code_url)?;
750	    let name = params.name.clone().unwrap_or(derived_name);
751	    let cwd = std::env::current_dir()?;
752	    let project_dir = cwd.join(&name);
753	
754	    let provisioner = if is_github_url(&code_url) {
755	        Provisioner::GhCreate
756	    } else {
757	        Provisioner::ExternalPreExisting
758	    };
759	    let gh_code_slug = if provisioner == Provisioner::GhCreate {
760	        Some(github_slug_from_url(&code_url)?)
761	    } else {
762	        None
763	    };
764	
765	    build_plan(
766	        scope,
767	        name,
768	        project_dir,
769	        code_url,
770	        provisioner,
771	        gh_code_slug,
772	    )
773	}
