974	/// Resolve a Path target to an absolute `PathBuf`. Handles `~`,
975	/// `~/X`, `$VAR`, `${VAR}` expansion; makes relative paths
976	/// absolute against cwd; lexically normalizes `.` / `..`. The
977	/// resulting path is **not** required to exist (init creates it).
978	fn resolve_path_target(p: &Path) -> Result<PathBuf, Box<dyn std::error::Error>> {
979	    let s = p.to_str().ok_or("path TARGET is not valid UTF-8")?;
980	    let expanded = expand_vars(s)?;
981	    let pb = PathBuf::from(&expanded);
982	    let abs = if pb.is_absolute() {
983	        pb
984	    } else {
985	        std::env::current_dir()?.join(pb)
986	    };
987	    Ok(normalize_path(&abs))
988	}
989	
990	/// Lexically normalize a path: collapse `.` / `..` components
991	/// without touching disk. `std::fs::canonicalize` requires the
992	/// path to exist, but init's destination doesn't yet.
993	fn normalize_path(p: &Path) -> PathBuf {
994	    let mut out: Vec<std::path::Component> = Vec::new();
995	    for comp in p.components() {
996	        match comp {
997	            std::path::Component::ParentDir => {
998	                let pop = matches!(
999	                    out.last(),
1000	                    Some(std::path::Component::Normal(_)) | Some(std::path::Component::CurDir)
1001	                );
1002	                if pop {
1003	                    out.pop();
1004	                } else {
1005	                    out.push(comp);
1006	                }
1007	            }
1008	            std::path::Component::CurDir => {}
1009	            other => out.push(other),
1010	        }
1011	    }
1012	    out.iter().collect()
1013	}
