1015	/// Extract the `owner/name` slug from a GitHub URL (any of the
1016	/// supported forms: SSH scp-like, `ssh://`, `https://`).
1017	fn github_slug_from_url(url: &str) -> Result<String, Box<dyn std::error::Error>> {
1018	    let stem = url.strip_suffix(".git").unwrap_or(url);
1019	    // The slug is the last two path components, `owner/name`.
1020	    if let Some(path) = stem
1021	        .strip_prefix("git@github.com:")
1022	        .or_else(|| stem.strip_prefix("ssh://git@github.com/"))
1023	        .or_else(|| stem.strip_prefix("https://github.com/"))
1024	        .or_else(|| stem.strip_prefix("http://github.com/"))
1025	    {
1026	        let parts: Vec<&str> = path.split('/').collect();
1027	        if parts.len() >= 2 {
1028	            return Ok(format!(
1029	                "{}/{}",
1030	                parts[parts.len() - 2],
1031	                parts[parts.len() - 1]
1032	            ));
1033	        }
1034	    }
1035	    Err(format!("cannot extract owner/name slug from GitHub URL '{url}'").into())
1036	}
