1041	    /// Delegate to the existing `From<&InitArgs>` impl in
1042	    /// [`crate::init::params`] (total — never fails).
1043	    fn to_params(&self) -> Result<Self::Params, String> {
1044	        Ok(InitParams::from(self))
1045	    }
