1053	/// Init entry point — runs the dual or POR provisioning flow.
1054	///
1055	/// Takes the shared `Context` (loaded user config) and the flat
1056	/// `InitParams`. CLI builds both at the binary edge in main.rs;
1057	/// tests construct `InitParams` directly.
1058	///
1059	/// `params.create_symlink` controls the `~/.claude/projects/`
1060	/// symlink side effect:
1061	///
1062	/// - `true` — CLI behavior; step 11 creates the symlink for
1063	///   dual-scope runs.
1064	/// - `false` — suppresses that side effect; used by test
1065	///   harnesses (`test_helpers::Fixture`, `test_helpers::FixturePor`)
1066	///   so parallel fixtures don't collide on the user's home dir.
1067	pub fn init(ctx: &Context, params: &InitParams) -> Result<(), Box<dyn std::error::Error>> {
1068	    debug!("init: enter");
1069	
1070	    let create_symlink = params.create_symlink;
1071	    let cfg = &ctx.user_config;
1072	    let plan = plan_init(params, cfg)?;
1073	    let is_dual = plan.scope.is_both();
1074	
1075	    // --- Preflight ---
1076	    info!("Preflight checks...");
1077	
1078	    debug!("verify jj is installed");
1079	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
1080	
1081	    if plan.provisioner == Provisioner::GhCreate {
1082	        debug!("verify gh CLI is installed + authenticated");
1083	        run("gh", &["auth", "status"], Path::new("."))
1084	            .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
1085	    }
1086	
1087	    if plan.project_dir.exists() {
1088	        return Err(format!("'{}' already exists", plan.project_dir.display()).into());
