1300	/// the signature for shape-symmetry with `create_dual`.
1301	fn create_por(
1302	    params: &InitParams,
1303	    plan: &InitPlan,
1304	    templates: Option<(PathBuf, Option<PathBuf>)>,
1305	    visibility: &str,
1306	    _create_symlink: bool,
