1364	fn create_dual(
1365	    params: &InitParams,
1366	    plan: &InitPlan,
1367	    templates: Option<(PathBuf, Option<PathBuf>)>,
1368	    visibility: &str,
1369	    create_symlink: bool,
1370	) -> Result<(), Box<dyn std::error::Error>> {
1371	    #[allow(clippy::unwrap_used)]
1372	    let session_dir = plan.session_dir.as_ref().unwrap(); // OK: scope=code,bot ⇒ session_dir set
1373	    #[allow(clippy::unwrap_used)]
