1383	    prepare_local_repo(&plan.project_dir, "code", code_template, &plan.name)?;
1384	    write_code_config(&plan.project_dir)?;
1385	    let code_chid = commit_initial(&plan.project_dir, "code", OchidStrategy::Placeholder)?;
1386	
