1447	/// Push primitive: steps 7, 8|9, 10 on `target`. Returns the
1448	/// final chid (`jj @-`) after re-init.
1449	///
1450	/// - `target` — repo working dir (already populated by
1451	///   `prepare_local_repo` + `commit_initial`).
1452	/// - `info_label` — narration tag (`"code"`, `"session"`, etc.).
1453	/// - `step_label_provision` — `"Step 8"` (session) or
1454	///   `"Step 9"` (code) — appears in the provision/push narration.
1455	/// - `clean_exclude` — `Some(".claude")` for work-side dual to
1456	///   preserve the nested bot repo across `git clean -xdf`;
1457	///   `None` otherwise.
1458	/// - `plan` / `params` / `visibility` / `remote_url` / `gh_slug` /
1459	///   `bare_path` — forwarded to `run_remote_step`.
1460	#[allow(clippy::too_many_arguments)]
1461	fn push_repo(
1462	    target: &Path,
1463	    info_label: &str,
1464	    step_label_provision: &str,
1465	    clean_exclude: Option<&str>,
1466	    plan: &InitPlan,
1467	    params: &InitParams,
1468	    visibility: &str,
1469	    remote_url: &str,
1470	    gh_slug: Option<&str>,
1471	    bare_path: Option<&Path>,
1472	) -> Result<String, Box<dyn std::error::Error>> {
1473	    info!("Step 7: Setting {info_label} bookmark and removing jj...");
1474	    debug!("place {info_label}-side main bookmark at the initial commit");
1475	    run("jj", &["bookmark", "set", "main", "-r", "@-"], target)?;
1476	    match clean_exclude {
1477	        Some(ex) => {
1478	            debug!("strip jj state from {info_label} side, preserving nested {ex}/");
1479	            run("git", &["clean", "-xdf", "--exclude", ex], target)?;
1480	        }
1481	        None => {
1482	            debug!("strip jj state from {info_label} side");
1483	            run("git", &["clean", "-xdf"], target)?;
1484	        }
1485	    }
1486	    debug!("re-attach {info_label} HEAD to main after clean");
1487	    run("git", &["checkout", "main"], target)?;
1488	
1489	    run_remote_step(
1490	        step_label_provision,
1491	        info_label,
1492	        plan,
1493	        remote_url,
1494	        gh_slug,
1495	        bare_path,
1496	        visibility,
1497	        target,
1498	        params,
1499	    )?;
1500	
1501	    info!("Step 10: Re-initializing jj on the {info_label} repo...");
1502	    debug!("re-colocate jj atop the now-remote-linked {info_label} repo");
1503	    run("jj", &["--quiet", "git", "init", "--colocate"], target)?;
1504	    debug!("restore {info_label}-side main bookmark after re-init");
1505	    run("jj", &["bookmark", "set", "main", "-r", "@-"], target)?;
1506	    debug!("enable jj tracking of {info_label}-side main against origin");
1507	    run(
1508	        "jj",
1509	        &["bookmark", "track", "main", "--remote=origin"],
1510	        target,
1511	    )?;
1512	    crate::common::verify_tracking(target, "main")?;
1513	    jj_chid("@-", target)
1514	}
1515	
1516	/// Execute Step 8 or Step 9 for one side.
1517	///
1518	/// - Provision the remote per the plan's provisioner.
1519	/// - Add `origin` and push `main` with retry.
1520	/// - Centralizing keeps both sides' step bodies identical.
1521	#[allow(clippy::too_many_arguments)]
1522	fn run_remote_step(
1523	    step_label: &str,
1524	    side_label: &str,
1525	    plan: &InitPlan,
1526	    remote_url: &str,
1527	    gh_slug: Option<&str>,
1528	    bare_path: Option<&Path>,
1529	    visibility: &str,
1530	    push_from: &Path,
1531	    params: &InitParams,
1532	) -> Result<(), Box<dyn std::error::Error>> {
1533	    match &plan.provisioner {
1534	        Provisioner::GhCreate => {
1535	            // Safe: GhCreate always supplies gh_slug.
1536	            #[allow(clippy::unwrap_used)]
1537	            let slug = gh_slug.unwrap(); // OK: GhCreate path always sets gh_slug
1538	            info!("{step_label}: Creating GitHub repo {slug} ({side_label})...");
1539	            debug!("create {side_label}-side remote on GitHub");
1540	            run(
1541	                "gh",
1542	                &["repo", "create", slug, visibility],
1543	                &plan.project_dir,
1544	            )?;
1545	        }
1546	        Provisioner::LocalBareInit => {
1547	            // Safe: LocalBareInit always supplies bare_path.
1548	            #[allow(clippy::unwrap_used)]
1549	            let bare = bare_path.unwrap(); // OK: LocalBareInit path always sets bare_path
1550	            info!(
1551	                "{step_label}: Initializing local bare repo at {} ({side_label})...",
1552	                bare.display()
1553	            );
1554	            debug!("init {side_label}-side bare repo as the local origin");
1555	            run(
1556	                "git",
1557	                &["init", "--bare", &bare.to_string_lossy()],
1558	                Path::new("."),
1559	            )?;
1560	        }
1561	        Provisioner::ExternalPreExisting => {
1562	            info!("{step_label}: Using pre-existing {side_label} remote {remote_url}");
1563	        }
1564	    }
1565	    debug!("point {side_label}-side git at its remote");
1566	    run("git", &["remote", "add", "origin", remote_url], push_from)?;
1567	    debug!("publish {side_label}-side initial commit; retry for GhCreate's async propagation");
1568	    run_retry(
1569	        "git",
1570	        &["push", "-u", "origin", "main"],
1571	        push_from,
1572	        &params.push_retry,
1573	    )?;
1574	    Ok(())
1575	}
1576	
1577	/// Split an `owner/name` slug. Errors if the shape is wrong (no `/`
1578	/// or more than one `/`).
1579	fn split_slug(slug: &str) -> Result<(&str, &str), Box<dyn std::error::Error>> {
1580	    let parts: Vec<&str> = slug.split('/').collect();
1581	    if parts.len() != 2 || parts[0].is_empty() || parts[1].is_empty() {
1582	        return Err(format!("unexpected GitHub slug '{slug}' (want 'owner/name')").into());
1583	    }
1584	    Ok((parts[0], parts[1]))
1585	}
