513	    UserConfig::default()
514	}
515	
516	fn cfg_top_level_remote(prefix: &str) -> UserConfig {
517	    let tl = AccountConfig {
518	        repo_default: Some("remote".into()),
519	        repo_category: HashMap::from([("remote".into(), prefix.into())]),
520	    };
521	    UserConfig {
522	        default_account: None,
523	        default_debug: None,
524	        top_level_repo: Some(tl),
525	        accounts: HashMap::new(),
526	        bot_session_items: None,
527	        bot_session_result_lines: None,
528	        bot_session_col_width: None,
529	    }
530	}
