532	fn cfg_top_level_local(parent: &str) -> UserConfig {
533	    let tl = AccountConfig {
534	        repo_default: Some("local".into()),
535	        repo_category: HashMap::from([("local".into(), parent.into())]),
536	    };
537	    UserConfig {
538	        default_account: None,
539	        default_debug: None,
540	        top_level_repo: Some(tl),
541	        accounts: HashMap::new(),
542	        bot_session_items: None,
543	        bot_session_result_lines: None,
544	        bot_session_col_width: None,
545	    }
