    let (_section, leaf) = section_and_leaf(key.path);
    let prefix = if key.required { "" } else { "# " };
    let value = render_value(key);
    out.push_str(&format!("{prefix}{leaf} = {value}\n"));
    out.push('\n');
    out
}

