//! Single source of truth for every settable config key across
//! vc-x1's two config homes (the user config file and the
//! per-repo workspace config).
//!
//! - `crate::config_cmd` prints this registry as an annotated
//!   schema, and — with `--validate` — checks a config file's keys
//!   against it (dynamic-segment aware).
//! - `crate::init` derives init's commented defaults from
//!   `schema()`, so these surfaces cannot drift from this list.

/// Which config home a key belongs to.
/// - `User` — `~/.config/vc-x1/config.toml`
/// - `WorkspaceCode` / `WorkspaceBot` — `<root>/.vc-config.toml`
///   in the work repo vs the `.claude` bot repo
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Home {
    User,
    WorkspaceCode,
    WorkspaceBot,
}

/// The value shape a key expects (for rendering / future typed
/// use).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ValueKind {
    Str,
    Usize,
    ItemList,
}

/// One settable configuration key.
pub struct ConfigKey {
    /// Dotted TOML path, e.g. `"bot-session.col-width"`.
    pub path: &'static str,
    /// Which home(s) accept this key.
    pub homes: &'static [Home],
    /// The value shape this key expects.
    pub kind: ValueKind,
    /// Rendered default, `None` if there is no default.
    pub default: Option<&'static str>,
    /// Active (not commented) in init; the value is role-specific.
    pub required: bool,
    /// The path has a `<placeholder>` segment matching a family
    /// of keys (e.g. `repo.category.<cat>`).
    pub dynamic: bool,
    /// One-line description.
    pub doc: &'static str,
    /// The command/flag or structural context this key is
    /// associated with (e.g. `"bot-session --col-width"`).
    pub used_by: &'static str,
}

/// Homes accepted by every `bot-session.*` key: all three homes,
/// since the user config and both workspace configs may each
/// carry a default.
const BOT_SESSION_HOMES: &[Home] = &[Home::User, Home::WorkspaceCode, Home::WorkspaceBot];

/// Homes accepted by workspace-only keys (`workspace.*`,
/// `push.*`): the two `.vc-config.toml` homes, never the user
/// config.
const WORKSPACE_HOMES: &[Home] = &[Home::WorkspaceCode, Home::WorkspaceBot];

/// The complete registry of settable keys.
///
/// - User home: `default.*`, `repo.*`, and the per-account
///   `account.<name>.repo.*` family.
/// - `bot-session.*`: accepted in all three homes.
/// - Workspace-only: `workspace.*`, `push.*`.
const SCHEMA: &[ConfigKey] = &[
    ConfigKey {
        path: "default.account",
        homes: &[Home::User],
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: false,
        doc: "Default account when --account is absent",
        used_by: "--account (init and account-aware commands)",
    },
    ConfigKey {
        path: "default.debug",
        homes: &[Home::User],
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: false,
        doc: "Default --debug value when used without an argument (reserved; not yet consumed)",
        used_by: "--debug (reserved; not yet consumed)",
    },
    ConfigKey {
        path: "repo.default",
        homes: &[Home::User],
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: false,
        doc: "Top-level shorthand: repo category to use when --repo is absent",
        used_by: "--repo (default category when --repo is bare)",
    },
    ConfigKey {
        path: "repo.category.<cat>",
        homes: &[Home::User],
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: true,
        doc: "Top-level shorthand: literal value for repo category <cat>",
        used_by: "--repo <cat> (init remote/local resolution)",
    },
    ConfigKey {
        path: "account.<name>.repo.default",
        homes: &[Home::User],
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: true,
        doc: "Per-account default repo category",
        used_by: "--account <name> with --repo",
    },
    ConfigKey {
        path: "account.<name>.repo.category.<cat>",
        homes: &[Home::User],
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: true,
        doc: "Per-account literal value for repo category <cat>",
        used_by: "--account <name> with --repo <cat>",
    },
    ConfigKey {
        path: "bot-session.items",
        homes: BOT_SESSION_HOMES,
        kind: ValueKind::ItemList,
        default: Some("headers,user,assistant,tool,summary"),
        required: false,
        dynamic: false,
        doc: "Default bot-session item set (comma-separated)",
        used_by: "bot-session --<item> / --no-<item> / --all / --none",
    },
    ConfigKey {
        path: "bot-session.result-lines",
        homes: BOT_SESSION_HOMES,
        kind: ValueKind::Usize,
        default: Some("10"),
        required: false,
        dynamic: false,
        doc: "Default --result-lines: max lines shown per tool result (0 = unlimited)",
        used_by: "bot-session --result-lines",
    },
    ConfigKey {
        path: "bot-session.col-width",
        homes: BOT_SESSION_HOMES,
        kind: ValueKind::Usize,
        default: Some("68"),
        required: false,
        dynamic: false,
        doc: "Default --col-width: first-column width in the field-inventory views",
        used_by: "bot-session --col-width",
    },
    ConfigKey {
        path: "workspace.path",
        homes: WORKSPACE_HOMES,
        kind: ValueKind::Str,
        default: None,
        required: true,
        dynamic: false,
        doc: "This repo's path relative to the workspace root (role-specific: \"/\" for the work repo, \"/.claude\" for the bot repo)",
        used_by: "find_workspace_root, sync, push, validate-desc (structural; written by init)",
    },
    ConfigKey {
        path: "workspace.other-repo",
        homes: WORKSPACE_HOMES,
        kind: ValueKind::Str,
        default: None,
        required: false,
        dynamic: false,
        doc: "Relative path to the counterpart repo; presence signals dual-repo mode (role-specific: \".claude\" for the work repo, \"..\" for the bot repo)",
        used_by: "default_scope, validate-desc/fix-desc --other-repo (structural)",
    },
    ConfigKey {
        path: "push.state-dir",
        homes: WORKSPACE_HOMES,
        kind: ValueKind::Str,
        default: Some(".vc-x1"),
        required: false,
        dynamic: false,
        doc: "Directory (relative to repo root) holding the push state file",
        used_by: "push / squash-push (state-file directory)",
    },
    ConfigKey {
        path: "push.state-file",
        homes: WORKSPACE_HOMES,
        kind: ValueKind::Str,
        default: Some("push-state.toml"),
        required: false,
        dynamic: false,
        doc: "Filename of the push state file under push.state-dir",
        used_by: "push / squash-push (state-file name)",
    },
];

/// Returns the complete registry of settable config keys.
pub fn schema() -> &'static [ConfigKey] {
    SCHEMA
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Finds a schema entry by its dotted path.
    ///
    /// - Panics if not found: tests only, and a missing key is a
    ///   test bug worth failing loudly on.
    #[allow(clippy::unwrap_used, clippy::expect_used)]
    fn find(path: &str) -> &'static ConfigKey {
        schema()
            .iter()
            .find(|k| k.path == path)
            .unwrap_or_else(|| panic!("schema key {path:?} not found"))
    }

    #[test]
    fn defaults_match_source_consts() {
        assert_eq!(
            find("bot-session.col-width").default,
            Some(crate::bot_session::COL_WIDTH.to_string()).as_deref()
        );
        assert_eq!(
            find("bot-session.result-lines").default,
            Some(crate::bot_session::RESULT_LINE_CAP.to_string()).as_deref()
        );
        assert_eq!(
            find("push.state-dir").default,
            Some(crate::push::DEFAULT_STATE_DIR)
        );
        assert_eq!(
            find("push.state-file").default,
            Some(crate::push::DEFAULT_STATE_FILE)
        );
    }

    #[test]
    fn paths_unique() {
        let mut paths: Vec<&str> = schema().iter().map(|k| k.path).collect();
        paths.sort_unstable();
        let mut deduped = paths.clone();
        deduped.dedup();
        assert_eq!(paths.len(), deduped.len(), "duplicate path(s) in schema()");
    }

    #[test]
    fn homes_non_empty() {
        for key in schema() {
            assert!(!key.homes.is_empty(), "{} has no homes", key.path);
        }
    }

    #[test]
    fn dynamic_keys_have_placeholder() {
        for key in schema() {
            let has_placeholder = key.path.contains('<');
            assert_eq!(
                key.dynamic, has_placeholder,
                "{}: dynamic={} but placeholder-presence={}",
                key.path, key.dynamic, has_placeholder
            );
        }
    }
}

//! The `config` subcommand: print the settable config schema,
//! grouped by config home then TOML section, sshd_config style.
//!
//! Read-only; consumes `crate::config_schema::schema()` — the
//! single source of truth for every settable key. `--home` filters
//! which home group(s) are printed.

use std::error::Error;

use clap::{Args, ValueEnum};

use log::{info, warn};

use crate::common::find_workspace_root;
use crate::config::config_path;
use crate::config_schema::{ConfigKey, Home, ValueKind, schema};
use crate::context::Context;
use crate::desc_helpers::VC_CONFIG_FILE;
use crate::subcommand::SubcommandRunner;
use crate::toml_simple::toml_load;

/// Which config home(s) to print.
#[derive(Clone, Copy, Debug, PartialEq, Eq, ValueEnum)]
#[value(rename_all = "kebab-case")]
pub enum HomeFilter {
    /// Only the user config (`~/.config/vc-x1/config.toml`).
    User,
    /// Only the workspace config (`<root>/.vc-config.toml`).
    Workspace,
    /// Both homes (default).
    All,
}

#[derive(Args, Debug)]
pub struct ConfigArgs {
    /// Which config home(s) to print: user, workspace, or all
    #[arg(long, value_enum, default_value_t = HomeFilter::All)]
    pub home: HomeFilter,

    /// Check the config file(s) for unknown/misspelled keys instead
    /// of printing the schema
    #[arg(long)]
    pub validate: bool,
}

/// Inputs to the `config` op, flat, owned, clap-free.
///
/// Mirrors `ConfigArgs`: `--home` (`home`), `--validate` (`validate`).
pub struct ConfigParams {
    pub home: HomeFilter,
    pub validate: bool,
}

impl From<&ConfigArgs> for ConfigParams {
    /// Convert clap-derived `ConfigArgs` into the flat
    /// `ConfigParams` (total — every field copies straight over).
    fn from(a: &ConfigArgs) -> Self {
        Self {
            home: a.home,
            validate: a.validate,
        }
    }
}

impl SubcommandRunner for ConfigArgs {
    type Params = ConfigParams;

    /// Delegate to the existing `From<&ConfigArgs>` impl above
    /// (total — never fails).
    fn to_params(&self) -> Result<Self::Params, String> {
        Ok(ConfigParams::from(self))
    }

    /// Run the `config` op.
    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
        config(ctx, params)
    }
}

/// A key belongs to the User group if any of its homes is
/// `Home::User`.
fn in_user_group(key: &ConfigKey) -> bool {
    key.homes.contains(&Home::User)
}

/// A key belongs to the Workspace group if any of its homes is
/// `Home::WorkspaceCode` or `Home::WorkspaceBot`.
fn in_workspace_group(key: &ConfigKey) -> bool {
    key.homes.contains(&Home::WorkspaceCode) || key.homes.contains(&Home::WorkspaceBot)
}

/// Split a dotted key path on its last `.` into `(section, leaf)`.
///
/// A path with no `.` (none exist in the current schema) falls
/// back to an empty section so the key still renders under a
/// blank `[]` header rather than panicking.
fn section_and_leaf(path: &str) -> (&str, &str) {
    match path.rfind('.') {
        Some(idx) => (&path[..idx], &path[idx + 1..]),
        None => ("", path),
    }
}

/// Render a key's value cell: the quoted/bare default, or an
/// angle-bracket placeholder by kind when there is no default —
/// except a required key with no default, which renders
/// `<required>` so it stands out.
fn render_value(key: &ConfigKey) -> String {
    match key.default {
        Some(d) => match key.kind {
            ValueKind::Usize => d.to_string(),
            ValueKind::Str | ValueKind::ItemList => format!("{d:?}"),
        },
        None => {
            if key.required {
                "<required>".to_string()
            } else {
                match key.kind {
                    ValueKind::Str => "<str>".to_string(),
                    ValueKind::Usize => "<usize>".to_string(),
                    ValueKind::ItemList => "<items>".to_string(),
                }
            }
        }
    }
}

/// Print one home group: a divider, then each key grouped by
/// section (schema order, first-seen section order), one
/// `[section]` header per section.
fn print_group(title: &str, path_hint: &str, keys: &[&ConfigKey]) {
    info!("# ── {title} config: {path_hint} ──");
    let mut sections: Vec<&str> = Vec::new();
    for key in keys {
        let (section, _leaf) = section_and_leaf(key.path);
        if !sections.contains(&section) {
            sections.push(section);
        }
    }
    for section in sections {
        info!("[{section}]");
        for key in keys {
            let (key_section, leaf) = section_and_leaf(key.path);
            if key_section != section {
                continue;
            }
            let prefix = if key.required { "" } else { "# " };
            let value = render_value(key);
            info!("{prefix}{leaf} = {value}   # {}", key.doc);
        }
    }
    info!("");
}

/// True if `actual` (a dotted key from a loaded config file) is
/// recognized by some `schema()` entry whose homes satisfy
/// `home_pred`.
///
/// - Non-dynamic entries match by exact path equality.
/// - Dynamic entries (`key.dynamic`) match segment-wise: equal
///   segment counts, each entry segment either equal to the actual
///   segment or a `<placeholder>` matching any single segment.
fn key_known(actual: &str, home_pred: impl Fn(&[Home]) -> bool) -> bool {
    schema().iter().any(|key| {
        if !home_pred(key.homes) {
            return false;
        }
        if !key.dynamic {
            return key.path == actual;
        }
        let entry_segs: Vec<&str> = key.path.split('.').collect();
        let actual_segs: Vec<&str> = actual.split('.').collect();
        entry_segs.len() == actual_segs.len()
            && entry_segs
                .iter()
                .zip(actual_segs.iter())
                .all(|(e, a)| e == a || (e.starts_with('<') && e.ends_with('>')))
    })
}

/// Validate one config file against the schema, filtered to the
/// homes accepted at that file by `home_pred`.
///
/// - A missing file is not an error — `info!`s that it's absent
///   and returns `Ok(0)`.
/// - Each key not recognized by `key_known` is reported with
///   `warn!`, naming `label` and the key; keys are checked in
///   sorted order for stable output.
/// - Returns the count of unknown keys found. A load error
///   (malformed TOML) propagates as `Err`.
fn validate_file(
    path: &std::path::Path,
    label: &str,
    home_pred: impl Fn(&[Home]) -> bool,
) -> Result<usize, Box<dyn Error>> {
    if !path.exists() {
        info!("{label}: {} not found — skipping", path.display());
        return Ok(0);
    }
    let map = toml_load(path)?;
    let mut keys: Vec<&String> = map.keys().collect();
    keys.sort();

    let mut unknown = 0;
    for key in keys {
        if !key_known(key, &home_pred) {
            warn!("{label} ({}): unknown key {key:?}", path.display());
            unknown += 1;
        }
    }
    Ok(unknown)
}

/// Validate the selected home(s)' config file(s) against the
/// schema, returning the total count of unknown keys.
fn validate(params: &ConfigParams) -> Result<usize, Box<dyn Error>> {
    let mut unknown = 0;

    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
        unknown += validate_file(&config_path()?, "user config", |homes| {
            homes.contains(&Home::User)
        })?;
    }

    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
        match find_workspace_root() {
            Some(root) => {
                unknown +=
                    validate_file(&root.join(VC_CONFIG_FILE), "workspace config", |homes| {
                        homes.contains(&Home::WorkspaceCode) || homes.contains(&Home::WorkspaceBot)
                    })?;
            }
            None => info!("workspace config: not inside a workspace — skipping"),
        }
    }

    Ok(unknown)
}

/// Print the settable config schema, grouped by config home then
/// TOML section (`--home` selects which home group(s) to print),
/// or — with `--validate` — check the config file(s) for unknown
/// keys and exit non-zero if any are found.
pub fn config(_ctx: &Context, params: &ConfigParams) -> Result<(), Box<dyn std::error::Error>> {
    if params.validate {
        let total = validate(params)?;
        return if total > 0 {
            Err(format!("config: {total} unknown key(s) found").into())
        } else {
            info!("config: all keys recognized");
            Ok(())
        };
    }

    info!(
        "# vc-x1 settable config keys (from vc-x1 {})",
        env!("CARGO_PKG_VERSION")
    );
    info!("");

    let all_keys = schema();

    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
        let user_keys: Vec<&ConfigKey> = all_keys.iter().filter(|k| in_user_group(k)).collect();
        print_group("User", "~/.config/vc-x1/config.toml", &user_keys);
    }

    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
        let workspace_keys: Vec<&ConfigKey> =
            all_keys.iter().filter(|k| in_workspace_group(k)).collect();
        print_group("Workspace", "<root>/.vc-config.toml", &workspace_keys);
    }

    Ok(())
}

